'use client';

interface Step {
  id: number;
  label: string;
}

interface StepIndicatorProps {
  steps: Step[];
  currentStep: number;
}

export function StepIndicator({ steps, currentStep }: StepIndicatorProps) {
  return (
    <div className="flex items-center gap-0">
      {steps.map((step, i) => {
        const isCompleted = step.id < currentStep;
        const isActive    = step.id === currentStep;
        const isLast      = i === steps.length - 1;

        return (
          <div key={step.id} className="flex items-center">
            <div className="flex flex-col items-center gap-1.5">
              <div className={[
                'flex h-7 w-7 items-center justify-center rounded-full text-[11px] font-bold transition-all duration-200',
                isCompleted ? 'bg-indigo-600 text-white'
                  : isActive ? 'bg-indigo-600/20 text-indigo-400 border border-indigo-500/40'
                  : 'bg-[#0c0c1a] text-zinc-700 border border-[#1e1e32]',
              ].join(' ')}>
                {isCompleted ? (
                  <svg width="10" height="10" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="3" strokeLinecap="round" strokeLinejoin="round">
                    <polyline points="20 6 9 17 4 12"/>
                  </svg>
                ) : step.id}
              </div>
              <span className={[
                'text-[10px] font-medium whitespace-nowrap',
                isActive ? 'text-indigo-400' : isCompleted ? 'text-zinc-400' : 'text-zinc-700',
              ].join(' ')}>
                {step.label}
              </span>
            </div>
            {!isLast && (
              <div className={[
                'h-px w-12 mb-4 mx-1 transition-all duration-200',
                isCompleted ? 'bg-indigo-600/40' : 'bg-[#1e1e32]',
              ].join(' ')} />
            )}
          </div>
        );
      })}
    </div>
  );
}
