'use client';

import { AuthInput } from '@/components/auth/AuthInput';

export interface RecipientData {
  recipientName:    string;
  recipientAccount: string;
  recipientBank:    string;
}

interface RecipientStepProps {
  data:      RecipientData;
  onChange:  (data: RecipientData) => void;
  errors:    Partial<RecipientData>;
  onClearError: (field: keyof RecipientData) => void;
}

const GHANA_BANKS = [
  'MTN Mobile Money',
  'Vodafone Cash',
  'AirtelTigo Money',
  'GCB Bank',
  'Ecobank Ghana',
  'Fidelity Bank Ghana',
  'Absa Bank Ghana',
  'Standard Chartered Ghana',
  'Zenith Bank Ghana',
  'CalBank',
];

export function RecipientStep({ data, onChange, errors, onClearError }: RecipientStepProps) {
  function set(field: keyof RecipientData, value: string) {
    onChange({ ...data, [field]: value });
    onClearError(field);
  }

  return (
    <div className="flex flex-col gap-5">
      <div>
        <h2 className="text-base font-semibold text-zinc-100">Recipient details</h2>
        <p className="mt-1 text-sm text-zinc-600">Who are you sending money to in Ghana?</p>
      </div>

      <AuthInput
        id="recipientName"
        label="Recipient full name"
        placeholder="Kwame Mensah"
        value={data.recipientName}
        onChange={(v) => set('recipientName', v)}
        error={errors.recipientName}
        autoComplete="off"
      />

      <div className="flex flex-col gap-1.5">
        <label htmlFor="recipientBank" className="text-[11px] font-semibold uppercase tracking-widest text-zinc-500">
          Bank / Mobile money
        </label>
        <select
          id="recipientBank"
          value={data.recipientBank}
          onChange={(e) => set('recipientBank', e.target.value)}
          className={[
            'w-full rounded-xl border bg-[#0c0c1a] px-4 py-3 text-sm text-zinc-100',
            'outline-none transition-all duration-150 focus:ring-1 appearance-none cursor-pointer',
            errors.recipientBank
              ? 'border-red-500/50 focus:border-red-500 focus:ring-red-500/20'
              : 'border-[#1e1e32] focus:border-indigo-500/50 focus:ring-indigo-500/20',
          ].join(' ')}
        >
          <option value="" disabled className="text-zinc-700">Select a bank or wallet</option>
          {GHANA_BANKS.map((bank) => (
            <option key={bank} value={bank} className="bg-[#0c0c1a]">{bank}</option>
          ))}
        </select>
        {errors.recipientBank && (
          <p className="text-[11px] text-red-400">{errors.recipientBank}</p>
        )}
      </div>

      <AuthInput
        id="recipientAccount"
        label="Account / Phone number"
        placeholder="0241234567"
        value={data.recipientAccount}
        onChange={(v) => set('recipientAccount', v)}
        error={errors.recipientAccount}
        autoComplete="off"
      />
    </div>
  );
}
